oxy_webhelp_navlinks = {"azr_configuration_cloud_acc-d30753e18314":{"topics":[{"title":"Creating Azure cloud accounts with OAuth","shortdesc":"<p class=\"shortdesc\">Create an Azure cloud account with OAuth configuration in <span class=\"ph\">RSC<\/span> to         protect Azure resources using a Microsoft Entra ID application.<\/p>","href":"saas\/azr_creating_cloud_account_oauth.html","attributes":{"data-id":"azr_creating_cloud_account_oauth"},"menu":{"hasChildren":false},"tocID":"azr_creating_cloud_account_oauth-d30753e18328","topics":[]},{"title":"Azure cloud account addition without OAuth","shortdesc":"<p class=\"shortdesc\">You can set up an Azure cloud account on <span class=\"ph\">RSC<\/span> using the Configure         without OAuth method and start protecting your Azure workloads.<\/p>","href":"saas\/azr_cloud_acc_addition_without_oauth.html","attributes":{"data-id":"azr_cloud_acc_addition_without_oauth"},"menu":{"hasChildren":false},"tocID":"azr_cloud_acc_addition_without_oauth-d30753e18342","next":"azr_cloud_acc_addition_without_oauth-d30753e18342"},{"title":"Azure cloud account addition using management group with OAuth","shortdesc":"<p class=\"shortdesc\">You can add multiple Azure subscriptions using an Azure management group with the         Configure with OAuth method. This method uses OAuth for authentication and automatically         configures the required roles and permissions.<\/p>","href":"saas\/azr_cld_acc_add_mgmt_grp_oauth.html","attributes":{"data-id":"azr_cld_acc_add_mgmt_grp_oauth"},"menu":{"hasChildren":false},"tocID":"azr_cld_acc_add_mgmt_grp_oauth-d30753e18436","next":"azr_cld_acc_add_mgmt_grp_oauth-d30753e18436"},{"title":"Azure cloud account addition with management group without OAuth","shortdesc":"<p class=\"shortdesc\">You can add multiple Azure subscriptions using an Azure management group with the         Configure without OAuth method. This method requires you to manually configure the service         principal permissions in the Azure portal before onboarding.<\/p>","href":"saas\/azr_cld_acc_add_mgmt_grp_without_oauth.html","attributes":{"data-id":"azr_cld_acc_add_mgmt_grp_without_oauth"},"menu":{"hasChildren":false},"tocID":"azr_cld_acc_add_mgmt_grp_without_oauth-d30753e18483","next":"azr_cld_acc_add_mgmt_grp_without_oauth-d30753e18483"},{"title":"Azure cloud account addition using Terraform","shortdesc":"<p class=\"shortdesc\">You can add multiple Azure cloud accounts to <span class=\"ph\">RSC<\/span> at once using the         RSC provider for Terraform.<\/p>","href":"saas\/azr_cloud_acc_addition_terraform.html","attributes":{"data-id":"azr_cloud_acc_addition_terraform"},"menu":{"hasChildren":false},"tocID":"azr_cloud_acc_addition_terraform-d30753e18516","topics":[]},{"title":"Creating an Azure cloud account for Data scanning","shortdesc":"<p class=\"shortdesc\">Create an Azure cloud account in <span class=\"ph\">RSC<\/span> for protection, and then enable         Data scanning. Data scanning helps you manage cloud posture risks.<\/p>","href":"saas\/azr_creating_cld_acc_data_scanning.html","attributes":{"data-id":"azr_creating_cld_acc_data_scanning"},"menu":{"hasChildren":false},"tocID":"azr_creating_cld_acc_data_scanning-d30753e18530","topics":[]},{"title":"Enabling Data scanning for Azure cloud accounts","shortdesc":"<p class=\"shortdesc\">Enable the Data scanning feature for an existing Azure cloud account in <span class=\"ph\">RSC<\/span>. Data scanning helps you manage cloud posture risks.<\/p>","href":"saas\/azure_enabling_data_scanning.html","attributes":{"data-id":"azure_enabling_data_scanning"},"menu":{"hasChildren":false},"tocID":"azure_enabling_data_scanning-d30753e18544","topics":[]}]}};